// E03S02 — AC1: Generate cryptographically random UUID token
// Scoped per-tech (not per-job) — one active token per tech at a time (AC3)
const techId = $input.item.json.tech_id || $input.item.json.body?.tech_id;

if (!techId) {
  throw new Error('tech_id is required — cannot generate magic link token without a tech_id');
}

// crypto.randomUUID() is available in Node.js 14.17+ (n8n runs Node 18+)
const token = require('crypto').randomUUID();

return [{ json: { tech_id: techId, token: token } }];

nodes.notes:
AC1: Uses crypto.randomUUID() — cryptographically secure UUID.
AC3: Token is per-tech, not per-job. Any previous token is overwritten by the PATCH.
Output: { tech_id: '<uuid>', token: '<uuid>' }

