// E03S02 — AC5: Log token PATCH failure — non-fatal
// The job is already assigned (jobs.status = Assigned, jobs.tech_id = set).
// This failure only means the tech SMS (E03S03) will not have a valid token.
// Downstream: E03S03 should check for a valid token before sending SMS.

const techId = $('Generate Magic Link Token').item.json.tech_id;
const patchResponse = $('PATCH techs — Store Token').item.json;

console.error('[SendJob] E03S02: magic_link_token PATCH failed for tech_id=' + techId);
console.error('[SendJob] PATCH response:', JSON.stringify(patchResponse));

return [{
  json: {
    error: 'magic_link_token PATCH failed',
    tech_id: techId,
    timestamp: new Date().toISOString(),
    patch_response: patchResponse
  }
}];
